mapper.sql:
where shop_id = #{shopId} and status != -1

    and name like concat('%', #{search.name}, '%')


    and category_id = #{search.categoryId}


    and status = #{search.status}

mapper.select:
select spu_id, category_id, shop_id, name, selling_point, main_img_url, img_urls, price_fee, market_price_fee, status, stock, sale_num, seq from spu where shop_id = #{shopId} and status = 1
and (category_id = #{categoryId} or category_id in ( select category_id from category where parent_id = #{categoryId} and status != -1 ))
order by seq asc, spu_id desc limit #{begin}, #{size}
